package com.theyawns.framework.dlq;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

/**
 * Tests for {@link FaultInjectionState}.
 *
 * @author Generated by Claude Code
 * @since 3.0
 */
@DisplayName("FaultInjectionState")
class FaultInjectionStateTest {

    private FaultInjectionState state;

    @BeforeEach
    void setUp() {
        state = new FaultInjectionState();
    }

    @Nested
    @DisplayName("Default state")
    class DefaultState {

        @Test
        @DisplayName("should be disabled by default")
        void shouldBeDisabledByDefault() {
            assertThat(state.isEnabled()).isFalse();
        }

        @Test
        @DisplayName("should have default failure message")
        void shouldHaveDefaultFailureMessage() {
            assertThat(state.getFailureMessage()).isEqualTo("Simulated fault injection failure");
        }
    }

    @Nested
    @DisplayName("Enable and disable")
    class EnableAndDisable {

        @Test
        @DisplayName("should enable fault injection")
        void shouldEnable() {
            state.setEnabled(true);
            assertThat(state.isEnabled()).isTrue();
        }

        @Test
        @DisplayName("should disable fault injection")
        void shouldDisable() {
            state.setEnabled(true);
            state.setEnabled(false);
            assertThat(state.isEnabled()).isFalse();
        }

        @Test
        @DisplayName("should set custom failure message")
        void shouldSetCustomMessage() {
            state.setFailureMessage("Custom failure");
            assertThat(state.getFailureMessage()).isEqualTo("Custom failure");
        }

        @Test
        @DisplayName("should reset to default message when null provided")
        void shouldResetToDefaultOnNull() {
            state.setFailureMessage("Custom");
            state.setFailureMessage(null);
            assertThat(state.getFailureMessage()).isEqualTo("Simulated fault injection failure");
        }
    }

    @Nested
    @DisplayName("checkAndThrow")
    class CheckAndThrow {

        @Test
        @DisplayName("should not throw when disabled")
        void shouldNotThrowWhenDisabled() {
            state.checkAndThrow(); // should not throw
        }

        @Test
        @DisplayName("should throw RuntimeException when enabled")
        void shouldThrowWhenEnabled() {
            state.setEnabled(true);
            assertThatThrownBy(() -> state.checkAndThrow())
                    .isInstanceOf(RuntimeException.class)
                    .hasMessage("Simulated fault injection failure");
        }

        @Test
        @DisplayName("should throw with custom message when enabled")
        void shouldThrowWithCustomMessage() {
            state.setEnabled(true);
            state.setFailureMessage("DLQ demo failure");
            assertThatThrownBy(() -> state.checkAndThrow())
                    .isInstanceOf(RuntimeException.class)
                    .hasMessage("DLQ demo failure");
        }
    }
}
